#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-23

# ============================================================================
# CC Version Ceiling
# ============================================================================
# Guards the UPPER bound of CC-version references (complements
# test-cc-version-floor.sh, which guards the lower bound). No authored body may
# cite a CC version NEWER than the live upstream head — that would be a typo'd,
# hallucinated, or premature claim about a version that does not exist yet.
#
# Ceiling = the newest entry in shared/cc-snapshots/ (cc-release-watch snapshots
# every upstream version). Deliberately NOT `latest_known` from cc-support.json:
# a manual_override can freeze latest_known BELOW the real head, which would make
# legitimate references to existing 2.1.184-186 features false-positive.
#
# Scope (tight + allowlist-first, to keep false-positives near zero):
#   - authored prose only: src/skills/**/*.md + src/agents/*.md (excl README.md)
#   - a token counts only when "CC" / "Claude Code" sits right before it
#   - generated mirrors (plugins/, docs/site/) and STAMPED constants
#     (cc-version-matrix.ts) are out of scope — they derive from the SoT.
#
# Issue: CC 2.1.186 adoption follow-up (over-fire remediation). Pairs with the
# verify gate in scripts/cc-triage.mjs.
# ============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

if [[ -t 1 ]]; then
    RED='\033[0;31m'; GREEN='\033[0;32m'; NC='\033[0m'
else
    RED=''; GREEN=''; NC=''
fi

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC Version Ceiling"
echo "=================="

# version_gt A B → exit 0 iff A > B (semver, via sort -V)
version_gt() {
    [[ "$1" != "$2" ]] && [[ "$(printf '%s\n%s\n' "$1" "$2" | sort -V | tail -1)" == "$1" ]]
}

# 1. Ceiling = newest snapshot on disk.
SNAP_DIR="$PROJECT_ROOT/shared/cc-snapshots"
# silent: best-effort  empty result is checked + fails loudly below
CEILING=$(ls "$SNAP_DIR" | grep -E '^[0-9]+\.[0-9]+\.[0-9]+\.md$' | sed 's/\.md$//' | sort -V | tail -1 || true)
if [[ -z "$CEILING" ]]; then
    log_fail "ceiling" "no version snapshots found in $SNAP_DIR"
    echo "Results: $PASS passed, $FAIL failed"; exit 1
fi
log_pass "ceiling (snapshot head) = $CEILING"

# 2. Self-test: prove the comparator actually flags an over-ceiling version, so a
#    future regression can't silently turn this into a no-op linter.
IFS='.' read -r cma cmi cpa <<< "$CEILING"
SYNTHETIC="$cma.$cmi.$((cpa + 1))"
if version_gt "$SYNTHETIC" "$CEILING"; then
    log_pass "comparator live: $SYNTHETIC > $CEILING is flagged"
else
    log_fail "comparator self-test" "failed to flag $SYNTHETIC > $CEILING"
fi

# 3. Scan authored prose for CC-context version tokens above the ceiling.
violations=0
scanned=0
while IFS= read -r f; do
    scanned=$((scanned + 1))
    # A token counts only when "CC" or "Claude Code" sits within a few non-digit
    # chars before it (covers "CC 2.1.x", "Claude Code >= 2.1.x", "CC v2.1.x").
    # silent: best-effort  grep no-match exits 1 under pipefail; empty is fine
    toks=$(grep -hoE '(CC|Claude Code)[^0-9]{0,8}2\.[0-9]+\.[0-9]+' "$f" | grep -oE '2\.[0-9]+\.[0-9]+' | sort -uV || true)
    for t in $toks; do
        if version_gt "$t" "$CEILING"; then
            log_fail "CC version above ceiling" "${f#"$PROJECT_ROOT"/} cites $t (> $CEILING)"
            violations=$((violations + 1))
        fi
    done
done < <(find "$PROJECT_ROOT/src/skills" "$PROJECT_ROOT/src/agents" -name '*.md' ! -name 'README.md')

if [[ $violations -eq 0 ]]; then
    log_pass "no CC version above ceiling across $scanned authored file(s)"
fi

echo ""
echo "Results: $PASS passed, $FAIL failed"
[[ $FAIL -eq 0 ]] || exit 1
